import p5 from 'https://cdn.jsdelivr.net/npm/p5@2/+esm';
const el = document.createElement('div'); el.style.height = '400px'; shadowRoot.appendChild(el);
const instance = new p5(p => {
  p.setup = () => { p.createCanvas(el.clientWidth || 640, 400); data.sketch.setup?.(p); };
  p.draw = () => data.sketch.draw?.(p);
}, el);
